import{_ as a,o as e,c as d,a6 as r}from"./chunks/framework.wLlb4ebq.js";const b=JSON.parse('{"title":"Web Clipper Adapter","description":"","frontmatter":{},"headers":[],"relativePath":"integrations/web-clipper.md","filePath":"integrations/web-clipper.md"}'),i={name:"integrations/web-clipper.md"};function l(n,t,o,h,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="web-clipper-adapter" tabindex="-1">Web Clipper Adapter <a class="header-anchor" href="#web-clipper-adapter" aria-label="Permalink to “Web Clipper Adapter”">​</a></h1><p>Web Clipper adapter 是未命中专用来源时的通用路径，用于从普通网页抽取标题、来源、摘要和正文线索，再导入 Notion 或 Obsidian。</p><h2 id="extraction-rules" tabindex="-1">Extraction rules <a class="header-anchor" href="#extraction-rules" aria-label="Permalink to “Extraction rules”">​</a></h2><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th></tr></thead><tbody><tr><td>Host filtering</td><td>排除搜索、邮箱、localhost 等不适合剪藏的页面</td></tr><tr><td>Title extraction</td><td>优先使用页面标题和 Open Graph / Twitter meta</td></tr><tr><td>Summary extraction</td><td>从 meta description、正文段落和可见文本中生成摘要</td></tr><tr><td>Charset handling</td><td>按响应头、HTML meta、回退编码尝试解码</td></tr><tr><td>Noise cleanup</td><td>去除 script、style、noscript、template 等噪声</td></tr></tbody></table><h2 id="metadata-fields" tabindex="-1">Metadata fields <a class="header-anchor" href="#metadata-fields" aria-label="Permalink to “Metadata fields”">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td>title</td><td>网页标题</td></tr><tr><td>url</td><td>当前页面 URL</td></tr><tr><td>site</td><td>域名或站点名</td></tr><tr><td>excerpt</td><td>摘要</td></tr><tr><td>charset</td><td>推断编码</td></tr><tr><td>capturedAt</td><td>捕获时间</td></tr></tbody></table><h2 id="normalized-schema-mapping" tabindex="-1">normalized schema mapping <a class="header-anchor" href="#normalized-schema-mapping" aria-label="Permalink to “normalized schema mapping”">​</a></h2><table tabindex="0"><thead><tr><th>Source field</th><th>normalizedContent field</th><th>Destination</th></tr></thead><tbody><tr><td>location.href</td><td>identity.url</td><td>链接</td></tr><tr><td>document title / meta title</td><td>content.title</td><td>标题</td></tr><tr><td>meta description / paragraph</td><td>content.excerpt</td><td>摘要</td></tr><tr><td>visible text</td><td>content.body</td><td>Markdown / Notion Blocks</td></tr><tr><td>hostname</td><td>metadata.sourceSite</td><td>来源站点</td></tr></tbody></table><h2 id="fallback-behavior" tabindex="-1">fallback behavior <a class="header-anchor" href="#fallback-behavior" aria-label="Permalink to “fallback behavior”">​</a></h2><table tabindex="0"><thead><tr><th>Failure</th><th>fallback behavior</th></tr></thead><tbody><tr><td>页面禁止访问</td><td>只保留标题和 URL</td></tr><tr><td>charset 解码失败</td><td>使用 UTF-8 结果并提示可能乱码</td></tr><tr><td>正文抽取为空</td><td>导出 metadata-only 条目</td></tr><tr><td>Notion 写入失败</td><td>保留预览，不伪造成功</td></tr><tr><td>Obsidian API 不可达</td><td>提示检查 Local REST API</td></tr></tbody></table><h2 id="known-limitations" tabindex="-1">Known limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to “Known limitations”">​</a></h2><ul><li>动态渲染页面可能缺少可抽取正文。</li><li>需要登录的内容通常只能抽取当前 DOM 可见部分。</li><li>通用抽取无法保证像专用 adapter 一样保留全部结构。</li></ul>',12)])])}const m=a(i,[["render",l]]);export{b as __pageData,m as default};
